request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?org ?orgId WHERE {
  ?participant a bboExt:Participant ;
               bbo:name ?pName ;
               tai:belongsTo ?choreo .
  FILTER(CONTAINS(LCASE(STR(?pName)), "manufacturer"))

  ?choreo tai:belongsTo ?modelDefs .
  ?modelDefs tai:belongsTo ?orgModel .
  ?orgModel a bboExt:Model .
  OPTIONAL { ?orgModel bbo:name ?modelName . }
  OPTIONAL { ?orgModel tai:organizationId ?orgId . }
  OPTIONAL { ?orgModel tai:belongsTo ?org . }
}
LIMIT 25
